import pygame
import sys

pygame.init()
pygame.mixer.init()
pygame.mixer.music.load("nothing_more.mp3")
pygame.mixer.music.set_volume(0.3)
pygame.mixer.music.play(-1)

# FENETRE
WIDTH, HEIGHT = 1280, 720
screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("URB-3x")
clock = pygame.time.Clock()

TILE_SIZE = 40

# CHARGEMENT IMAGES
background = pygame.image.load("background_forest.png")
background = pygame.transform.scale(background, (WIDTH, HEIGHT))

player_texture = pygame.image.load("URB-3x/player.png")
player_texture = pygame.transform.scale(player_texture, (30, 40))

# TEXTURES PAR BIOME
textures = {
    "1": {
        "1": pygame.image.load("URB-3x/ground_jungle.png"),
        "2": pygame.image.load("URB-3x/ground_city.png"),
        "3": pygame.image.load("URB-3x/ground_waterways.png"),
        "4": pygame.image.load("URB-3x/ground_lab-s.png"),
        "5": pygame.image.load("URB-3x/ground_lab-u.png"),
        "6": pygame.image.load("URB-3x/ground_cave.png")
    },
    "U": {
        "1": pygame.image.load("URB-3x/underground_jungle.png"),
        "2": pygame.image.load("URB-3x/underground_city.png"),
        "3": pygame.image.load("URB-3x/Error.png"),
        "4": pygame.image.load("URB-3x/underground_lab.png"),
        "5": pygame.image.load("URB-3x/Error.png"),
        "6": pygame.image.load("URB-3x/underground_cave.png")
    },
    "W": {
        "1": pygame.image.load("URB-3x/wall_jungle.png"),
        "2": pygame.image.load("URB-3x/wall_city.png"),
        "3": pygame.image.load("URB-3x/Error.png"),
        "4": pygame.image.load("URB-3x/wall_lab-s.png"),
        "5": pygame.image.load("URB-3x/wall_lab-u.png"),
        "6": pygame.image.load("URB-3x/Error.png")
    },
    "2": {
        "1": pygame.image.load("URB-3x/damage_jungle.png"),
        "2": pygame.image.load("URB-3x/damage_city.png"),
        "3": pygame.image.load("URB-3x/damage_waterways.png"),
        "4": pygame.image.load("URB-3x/Error.png"),
        "5": pygame.image.load("URB-3x/damage_lab-u.png"),
        "6": pygame.image.load("URB-3x/damage_cave.png")
    },
    "3": {
        "1": pygame.image.load("URB-3x/upward_jungle.png"),
        "2": pygame.image.load("URB-3x/upward_city.png"),
        "3": pygame.image.load("URB-3x/Error.png"),
        "4": pygame.image.load("URB-3x/Error.png"),
        "5": pygame.image.load("URB-3x/upward_lab-u.png"),
        "6": pygame.image.load("URB-3x/Error.png")
    },
    "4": {
        "1": pygame.image.load("URB-3x/backward_jungle.png"),
        "2": pygame.image.load("URB-3x/backward_city.png"),
        "3": pygame.image.load("URB-3x/Error.png"),
        "4": pygame.image.load("URB-3x/backward_lab-s.png"),
        "5": pygame.image.load("URB-3x/Error.png"),
        "6": pygame.image.load("URB-3x/Error.png")
    },
    "L": {
        "1": pygame.image.load("URB-3x/ladder_jungle.png"),
        "2": pygame.image.load("URB-3x/ladder_city.png"),
        "3": pygame.image.load("URB-3x/ladder_waterways.png"),
        "4": pygame.image.load("URB-3x/ladder_lab-s.png"),
        "5": pygame.image.load("URB-3x/ladder_lab-u.png"),
        "6": pygame.image.load("URB-3x/Error.png")
    }
}

# SCALE
for tile_type in textures:
    for biome in textures[tile_type]:
        textures[tile_type][biome] = pygame.transform.scale(
            textures[tile_type][biome], (TILE_SIZE, TILE_SIZE)
        )

# MAP
level_map = [
    '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''
]

biome_map = [
'', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''
]

biome_names = {
    "1": "jungle",
    "2": "ville",
    "3": "waterways",
    "4": "lab-s",
    "5": "lab-u",
    "6": "cave",
}

ACTIVE_MARGIN = 50
def is_visible(rect):
    return (
        rect.right >= camera_x - ACTIVE_MARGIN and
        rect.left <= camera_x + WIDTH + ACTIVE_MARGIN and
        rect.bottom >= camera_y - ACTIVE_MARGIN and
        rect.top <= camera_y + HEIGHT + ACTIVE_MARGIN
    )

ground_tiles = []
damage_tiles = []
upward_tiles = []
backward_tiles = []
underground_tiles =[]
ladder_tiles = []
wall_tiles = []

spawn_x = 100
spawn_y = 100

# LECTURE BIOME MAP
biome_tiles = {}
for y, row in enumerate(biome_map):
    for x, biome in enumerate(row):
        biome_tiles[(x, y)] = biome

# LECTURE MAP
for y, row in enumerate(level_map):
    for x, tile in enumerate(row):

        world_x = x * TILE_SIZE
        world_y = y * TILE_SIZE

        biome = biome_tiles.get((x, y), "0")

        if tile == "1":
            ground_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "1"
            })

        if tile == "2":
            damage_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "2"
            })
        
        if tile == "3":
            upward_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "3"
            })

        if tile == "4":
            backward_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "4"
            })
        
        if tile == "U":
            underground_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "U"
            })
        
        if tile == "W":
            wall_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "W"
            })

        if tile == "L":
            ladder_tiles.append({
                "rect": pygame.Rect(world_x, world_y, TILE_SIZE, TILE_SIZE),
                "biome": biome,
                "type": "L"
            })

        if tile == "P":
            spawn_x = world_x
            spawn_y = world_y

player = pygame.Rect(spawn_x, spawn_y, 30, 40)

vel_y = 0
speed = 8.5
jump_power = -13
gravity = 0.7
on_ground = False

camera_x = 0
camera_y = 0

def respawn():
    global vel_y
    player.x = spawn_x
    player.y = spawn_y
    vel_y = 0

# GAME LOOP
while True:

    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            pygame.quit()
            sys.exit()

    keys = pygame.key.get_pressed()

    dx = 0
    dy = 0

    if keys[pygame.K_q]:
        dx -= speed
    if keys[pygame.K_d]:
        dx += speed

    on_ladder = False
    for tile in ladder_tiles:
        if not is_visible(tile["rect"]):
            continue
        if player.colliderect(tile["rect"]):
            on_ladder = True

    on_top_of_ladder = False
    for tile in ladder_tiles:
        if not is_visible(tile["rect"]):
            continue
        rect = tile["rect"]
        if (
            player.bottom <= rect.top + 10 and
            player.bottom >= rect.top - 10 and
            player.right > rect.left and
            player.left < rect.right
        ):
            on_top_of_ladder = True

    if on_ladder:
        vel_y = 0

        if keys[pygame.K_z]:
            player.y -= 4
        if keys[pygame.K_s]:
            player.y += 4

    if keys[pygame.K_SPACE] and on_ground and not on_ladder:
        vel_y = jump_power
    if keys[pygame.K_SPACE] and on_top_of_ladder:
        vel_y = jump_power

    if not on_ladder:
        vel_y += gravity
        dy += vel_y

    player.x += dx

    for tile in ground_tiles:
        if not is_visible(tile["rect"]):
            continue
        rect = tile["rect"]
        if player.colliderect(rect):
            if dx > 0:
                player.right = rect.left
            if dx < 0:
                player.left = rect.right
    
    for tile in wall_tiles:
        if not is_visible(tile["rect"]):
            continue
        rect = tile["rect"]
        if player.colliderect(rect):
            if dx > 0:
                player.right = rect.left
            if dx < 0:
                player.left = rect.right

    player.y += dy
    on_ground = False
    current_biome_name = "void"

    for tile in ground_tiles:
        if not is_visible(tile["rect"]):
            continue
        rect = tile["rect"]
        if player.colliderect(rect):
            if vel_y > 0:
                player.bottom = rect.top
                vel_y = 0
                on_ground = True
                current_biome_name = biome_names.get(tile["biome"], "inconnu")
            elif vel_y < 0:
                player.top = rect.bottom
                vel_y = 0
    
    for tile in wall_tiles:
        if not is_visible(tile["rect"]):
            continue
        rect = tile["rect"]
        if player.colliderect(rect):
            if vel_y > 0:
                player.bottom = rect.top
                vel_y = 0
                on_ground = True
                current_biome_name = biome_names.get(tile["biome"], "inconnu")
            elif vel_y < 0:
                player.top = rect.bottom
                vel_y = 0

    for tile in damage_tiles:
        if not is_visible(tile["rect"]):
            continue
        if player.colliderect(tile["rect"]):
            respawn()

    camera_x = player.centerx - WIDTH // 2
    camera_y = player.centery - HEIGHT // 2

    pygame.display.set_caption("URB-3x")

    screen.blit(background, (0, 0))

    # RENDU AVEC BIOME
    for tile in ground_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))
    
    for tile in wall_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))

    for tile in damage_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))

    for tile in ladder_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))

    for tile in backward_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))
    
    for tile in underground_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))

    screen.blit(player_texture, (player.x - camera_x, player.y - camera_y))

    for tile in upward_tiles:
        if is_visible(tile["rect"]):
            texture = textures[tile["type"]][tile["biome"]]
            screen.blit(texture, (tile["rect"].x - camera_x, tile["rect"].y - camera_y))

    pygame.display.update()
    clock.tick(60)
